           where owner_event_type = 'core_lesson_event' and owner_event_id = any(ids))
       into n;
  if n > 0 then
    raise exception 'Grade 5 day-level load aborted: % teacher-attached row(s) (fork/completion/board/section/comment/resource) reference the week-summary lessons being soft-deleted — resolve them first', n;
  end if;
  update master_core_lesson_events
     set deleted_at = now(), updated_at = now()
   where deleted_at is null and id = any(ids);
end $$;

-- ── 3. The 1054 day-level lessons (idempotent upserts) ──────────────────
