insert into master_core_lesson_events
  (id, unit_id, subject_id, week_number, day_of_week, title, directions, learning_objectives, notes, resources, standards, display_order_within_day)
  values ('a992d84c-f056-5b3d-92e6-8acc681ff79a', 'a3af9977-9ab6-5857-9cb0-68a3faab31db', '00000000-0000-0000-0000-0000000005d7', 7, 'mon'::weekday, 'This week we are going to find out about transforming materials.', 'This week we are going to find out about transforming materials.
Today we are going to look at Physical Changes
Looking at ice, chocolate and butter - using a scale, 3 beakers, a timer and an electric skillet.

Observe.
1. Which solid will melt the fastest? Predict the results.
2. Place each solid in a separate beaker and put in the skillet. Observe what happens.
3. Note the temperature on the skillet - 100 degrees centigrade is the boiling point of water.
4. Measure the time it takes for each solid to melt.
5. Order the results in a graph.
6. What will happen next? Are the changes permanent?
7. How can you turn them back to a solid?

Students can try and change the material back to a solid, how might that work?

Examples of Physical and Chemical Changes ( Updated )', '[]'::jsonb, 'Std: Can say if it is a physical or chemical change

Assessment: What change has happened?

Differentiation: Can say the words physical or chemical
Can identify a physical or chemical change some of the time correctly
Can correctly identify physical and chemical changes correctly', '[]'::jsonb, '{}'::uuid[], 6)
