insert into master_core_lesson_events
  (id, unit_id, subject_id, week_number, day_of_week, title, directions, learning_objectives, notes, resources, standards, display_order_within_day)
  values ('57436b54-e76e-5385-a7bb-6b728f1023fe', '26d7d07b-c350-518f-ab6d-c9775b3a00dd', '00000000-0000-0000-0000-0000000005d4', 9, 'sun'::weekday, 'Grammar', 'Grammar:
Brainpop: Punctuation
Warm-up (3 minutes)
Write three sentences on the board:
"The dog ran outside"
"Where is the dog"
"Look at that dog"
Ask students what’s missing from these sentences.
Mini-Lesson (5 minutes)
Introduce the three types of end marks:
Period (.): Used to end a statement.
Question mark (?): Used at the end of a question.
Exclamation mark (!): Used to show strong feeling or excitement.
Give examples of each:
"The dog ran outside." (statement)
"Where is the dog?" (question)
"Look at that dog!" (exclamation)
Activity (5 minutes)
Write sentences on the board without end marks, and have students decide which end mark to use:
"It is raining outside"
"Do you like ice cream"
"What a beautiful day"
Wrap-up (2 minutes)
Have students share with a partner one sentence using a period, one using a question mark, and one using an exclamation mark.', '[]'::jsonb, '', '[]'::jsonb, '{}'::uuid[], 3)
