  values ('28b1d14c-d586-5e5c-8589-1ae6967cd005', 'a3af9977-9ab6-5857-9cb0-68a3faab31db', '00000000-0000-0000-0000-0000000005d7', 9, 'sun'::weekday, 'The next few weeks will look at an investigation to start off the week in…', 'The next few weeks will look at an investigation to start off the week in continuing to expose students to scientific knowledge/experiences in order to be successful in the task completed for the final task as outlined in the rubric:

