  values ('4e4d906d-393e-5a57-b75f-ce37d7d80b68', '75b855d8-0195-5036-89e0-2431feb4e28a', '00000000-0000-0000-0000-0000000005d1', 16, 'wed'::weekday, 'Lesson 4: 3D "Architects at Work: Designing with 3D Shapes!"', 'Lesson 4: 3D "Architects at Work: Designing with 3D Shapes!"', '[]'::jsonb, 'Std: Learning Objective: Students will be able to combine various 3D shapes to create new structures and will accurately use math vocabulary to describe the attributes of the shapes and the structures they build.

