insert into master_core_lesson_events
  (id, unit_id, subject_id, week_number, day_of_week, title, directions, learning_objectives, notes, resources, standards, display_order_within_day)
  values ('f7ae182f-6695-50fc-8f02-c19661c5dbe9', '9b1e6479-fc29-52b2-b3ba-be1522f28f4c', '00000000-0000-0000-0000-0000000005d7', 17, 'wed'::weekday, 'Key Vocabulary', 'Key Vocabulary
source, primary, secondary

Primary and Secondary Sources
Intro (10mins):
Show an old photograph (or drawing).
Tell students:
“This is a primary source.”
“Primary means from the past.”
Explain with examples:
old photo.; old newspaper; object from long ago.

You can use gesture: Point behind you when you say past
Show an information book or point to yourself.
“This is a secondary source.”
“Secondary means it tells us about the past.”
Explain: books, teachers, videos explaining the past, websites
You can gesture: Point to mouth (telling)
Activity: (20 mins)
Anchor Chart - Draw on board:

Go over the intro and invite students to give examples and discuss.
Wrap-up: (10 mins):
Sorting Activity:
Word cards:
Old photo, newspaper, information book, teacher
Two labels:
PRIMARY
SECONDARY', '["Tell the difference between primary and secondary sources."]'::jsonb, 'Std: Identify and classify historical sources

Assessment: Putting sources in Primary and Secondary categories

Differentiation: 🟢✔ pointing
🔵 ✔ short explanations
🟣 ✔ full sentence explanations', '[]'::jsonb, '{}'::uuid[], 6)
