  values ('e4615c5d-ad4b-5cf5-98ff-b4238c4fca4d', '28e56d40-c191-52c4-8b1e-be172fdb38f5', '00000000-0000-0000-0000-0000000005d2', 27, 'wed'::weekday, 'Guided Reading:/Grammar', 'Guided Reading:/Grammar:

 Quick Review- https://docs.google.com/presentation/d/1TOHLKvkX9KRQea1Vbg0Tktm9N8UobUPc/edit?usp=drive_link&ouid=115321778441106560721&rtpof=true&sd=true

