-- ── 5. Verification (run separately; kept as comments) ─────────────────────
-- Expected after load:
--   active day-level lessons: 1054 (math=163, reading=158, writing=144, grammar=121, spelling=135, ufli=33, explorers=149, sel=151)
--   per day: sun=201, mon=207, tue=217, wed=221, thu=208
--   plus 15 active week-35-37 summaries = 1069 active total; 170 soft-deleted.
--
-- select s.color as subject, m.day_of_week, count(*)
--   from master_core_lesson_events m join subjects s on s.id = m.subject_id
--   join units u on u.id = m.unit_id
--  where u.school_year_id = '00000000-0000-0000-0000-0000000000c2'
--    and m.deleted_at is null
--  group by 1, 2 order by 1, 2;
--
-- select count(*) as active_total
--   from master_core_lesson_events m join units u on u.id = m.unit_id
--  where u.school_year_id = '00000000-0000-0000-0000-0000000000c2'
--    and m.deleted_at is null;                       -- expect 1069
--
-- select count(*) as soft_deleted
--   from master_core_lesson_events m join units u on u.id = m.unit_id
--  where u.school_year_id = '00000000-0000-0000-0000-0000000000c2'
--    and m.deleted_at is not null;                   -- expect 170
--
-- select day_of_week, count(*) from master_core_lesson_events
--  where week_number between 35 and 37 and deleted_at is null
--  group by 1 order by 1;                             -- expect 3 per weekday
